def run_r_oracle(self, test_spec, data_file):
    """Run R Oracle and return result file"""
    temp_dir = tempfile.mkdtemp()
    output_file = Path(temp_dir) / "oracle_result.csv"

    try:
        cmd = [
            "docker", "run", "--rm",
            "-v", f"{data_file}:/data.csv:ro",
            "-v", f"{temp_dir}:/output_dir",
            "stats-rs-oracle",
            test_spec["test_type"],
            "/data.csv",
            "/output_dir/oracle_result.csv"
        ]

        if "formula" in test_spec:
            cmd.append(test_spec["formula"])

