//! Comprehensive R comparison benchmarks
//!
//! This benchmark suite compares our Rust implementation against R's lm()
//! to validate we're meeting our performance targets as defined in CLAUDE.md:
//! - Linear Models: ≥2x faster than R's lm()

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use stats_models::Lm;
use std::fs::File;
use std::io::Write;
use std::process::Command;
use std::time::{SystemTime, UNIX_EPOCH};

/// Generate test data for benchmarking
fn generate_test_data(n_obs: usize, n_vars: usize) -> (Vec<f64>, Vec<f64>) {
    // Create design matrix with intercept + random variables
    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    let mut y_data = Vec::with_capacity(n_obs);

    // Simple deterministic data generation for consistent benchmarks
    for i in 0..n_obs {
        // Intercept column
        x_data.push(1.0);

        // Generate predictors
        for j in 1..n_vars {
            x_data.push((i as f64 + j as f64) * 0.1);
        }

        // Generate response (linear combination + small noise)
        let y = 1.0
            + (0..n_vars - 1)
                .map(|j| (i as f64 + j as f64) * 0.1 * 0.5)
                .sum::<f64>()
            + (i as f64 * 0.01).sin() * 0.1;
        y_data.push(y);
    }

    (x_data, y_data)
}

/// Create CSV file for R benchmarking
fn create_r_data_file(x_data: &[f64], y_data: &[f64], n_obs: usize, n_vars: usize) -> String {
    let timestamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_nanos();
    let filename = format!("/tmp/r_bench_data_{}_{}.csv", std::process::id(), timestamp);

    let mut file = File::create(&filename).expect("Failed to create CSV file");

    // Write header
    write!(file, "y").unwrap();
    for i in 1..n_vars {
        write!(file, ",x{}", i).unwrap();
    }
    writeln!(file).unwrap();

    // Write data
    for i in 0..n_obs {
        write!(file, "{}", y_data[i]).unwrap();
        for j in 1..n_vars {
            write!(file, ",{}", x_data[i * n_vars + j]).unwrap();
        }
        writeln!(file).unwrap();
    }

    filename
}

/// Benchmark R's lm() function (simplified version)
fn benchmark_r_lm(data_file: &str, n_vars: usize) -> f64 {
    // Create formula string
    let mut formula = "y ~ ".to_string();
    for i in 1..n_vars {
        if i > 1 {
            formula.push_str(" + ");
        }
        formula.push_str(&format!("x{}", i));
    }

    // Create R script for timing (single run for simplicity)
    let script = format!(
        r#"
        data <- read.csv("{}")
        start_time <- proc.time()
        fit <- lm({}, data = data)
        end_time <- proc.time()
        elapsed <- (end_time - start_time)[3] * 1000  # Convert to milliseconds
        cat(sprintf("%.3f", elapsed))
        "#,
        data_file, formula
    );

    let timestamp = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_nanos();
    let script_file = format!("/tmp/r_bench_script_{}_{}.R", std::process::id(), timestamp);

    let mut file = File::create(&script_file).expect("Failed to create R script");
    file.write_all(script.as_bytes()).unwrap();

    // Run R script with timeout
    let output = Command::new("timeout")
        .arg("10") // 10 second timeout
        .arg("Rscript")
        .arg(&script_file)
        .output()
        .expect("Failed to run R script");

    // Clean up immediately
    std::fs::remove_file(&script_file).ok();

    if !output.status.success() {
        println!(
            "R script failed: {}",
            String::from_utf8_lossy(&output.stderr)
        );
        return 999.0; // Return high value if R fails
    }

    let elapsed_str = String::from_utf8_lossy(&output.stdout);
    elapsed_str.trim().parse().unwrap_or(999.0)
}

/// Check if R is available for benchmarking
fn r_available() -> bool {
    Command::new("Rscript")
        .arg("--version")
        .output()
        .map(|output| output.status.success())
        .unwrap_or(false)
}

fn bench_rust_vs_r_small(c: &mut Criterion) {
    let (x_data, y_data) = generate_test_data(50, 3); // 50 obs, 3 variables (incl intercept)

    // Benchmark Rust implementation
    c.bench_function("rust_lm_50x3", |b| {
        b.iter(|| {
            let _fit = Lm::fit(&x_data, &y_data, 50, 3).unwrap();
        })
    });

    // Run R comparison separately (not in criterion loop to avoid hanging)
    println!("\n=== R COMPARISON RESULTS ===");
    if r_available() {
        let data_file = create_r_data_file(&x_data, &y_data, 50, 3);
        let r_time_ms = benchmark_r_lm(&data_file, 3);
        std::fs::remove_file(data_file).ok();

        println!("R lm() time for 50x3: {:.3} ms", r_time_ms);
    } else {
        println!("Skipping R comparison: R not available");
    }
}

fn bench_rust_vs_r_medium(c: &mut Criterion) {
    let (x_data, y_data) = generate_test_data(100, 5); // 100 obs, 5 variables

    c.bench_function("rust_lm_100x5", |b| {
        b.iter(|| {
            let _fit = Lm::fit(&x_data, &y_data, 100, 5).unwrap();
        })
    });

    if r_available() {
        let data_file = create_r_data_file(&x_data, &y_data, 100, 5);
        let r_time_ms = benchmark_r_lm(&data_file, 5);
        std::fs::remove_file(data_file).ok();

        println!("R lm() time for 100x5: {:.3} ms", r_time_ms);
    }
}

fn bench_rust_vs_r_large(c: &mut Criterion) {
    let (x_data, y_data) = generate_test_data(1000, 10); // 1000 obs, 10 variables

    c.bench_function("rust_lm_1000x10", |b| {
        b.iter(|| {
            let _fit = Lm::fit(&x_data, &y_data, 1000, 10).unwrap();
        })
    });

    if r_available() {
        let data_file = create_r_data_file(&x_data, &y_data, 1000, 10);
        let r_time_ms = benchmark_r_lm(&data_file, 10);
        std::fs::remove_file(data_file).ok();

        println!("R lm() time for 1000x10: {:.3} ms", r_time_ms);
    }
}

fn bench_rust_scaling(c: &mut Criterion) {
    let mut group = c.benchmark_group("rust_scaling");

    for &size in &[50, 100, 200, 500] {
        let n_vars = (size as f64).sqrt() as usize + 1; // Scale variables with size
        let (x_data, y_data) = generate_test_data(size, n_vars);

        group.bench_with_input(
            BenchmarkId::new("rust_lm", format!("{}x{}", size, n_vars)),
            &(x_data, y_data, size, n_vars),
            |b, (x_data, y_data, n_obs, n_vars)| {
                b.iter(|| {
                    let _fit = Lm::fit(x_data, y_data, *n_obs, *n_vars).unwrap();
                })
            },
        );
    }

    group.finish();
}

criterion_group!(
    benches,
    bench_rust_vs_r_small,
    bench_rust_vs_r_medium,
    bench_rust_vs_r_large,
    bench_rust_scaling
);
criterion_main!(benches);

