    let avg_time_ms = duration.as_secs_f64() / 100.0 * 1000.0;
    println!("Rust Lm::fit average time for 1000x10: {:.3} ms", avg_time_ms);

    // Also test single run
    let start = Instant::now();
    let _fit = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
    let single_time = start.elapsed();
    println!("Rust Lm::fit single run for 1000x10: {:.3} ms", single_time.as_secs_f64() * 1000.0);
}

