use std::time::Instant;
use stats_models::Lm;

fn main() {
    let n_obs = 1000;
    let n_vars = 11; // 10 + intercept

    // Generate test data
    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    let mut y_data = Vec::with_capacity(n_obs);

    for i in 0..n_obs {
        x_data.push(1.0); // intercept
        let mut y = 0.0;
        for j in 1..n_vars {
            let x_val = (i as f64 + j as f64) * 0.1;
            x_data.push(x_val);
            y += x_val * 0.1;
        }
        y += (i as f64 * 0.01).sin() * 0.1;
        y_data.push(y);
    }

    // Warm up
    for _ in 0..10 {
        let _ = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
    }

    // Time 100 iterations
    let start = Instant::now();
    for _ in 0..100 {
        let _ = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
    }
    let duration = start.elapsed();

    let avg_time_ms = duration.as_secs_f64() / 100.0 * 1000.0;
    println!("Rust Lm::fit average time for 1000x10: {:.3} ms", avg_time_ms);

    // Also test single run
    let start = Instant::now();
    let _fit = Lm::fit(&x_data, &y_data, n_obs, n_vars).unwrap();
    let single_time = start.elapsed();
    println!("Rust Lm::fit single run for 1000x10: {:.3} ms", single_time.as_secs_f64() * 1000.0);
}

