     1→//! High-level statistical modeling API for Rust
     2→//!
     3→//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
     4→//! and `Glm` (Generalized Linear Models), integrating lower-level crates
     5→//! to provide a complete modeling workflow.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use faer::{prelude::*, Mat};
    11→use family::Family;
    12→use link::LinkFn;
    13→use ndarray::{Array1, ArrayView1, ArrayView2};
    14→use optimcore::{irls, IrlsConfig};
    15→
    16→/// Statistical modeling errors
    17→#[derive(thiserror::Error, Debug)]
    18→pub enum ModelError {
    19→    /// Linear algebra computation error
    20→    #[error("Linear algebra error: {0}")]
    21→    LinearAlgebra(String),
    22→    /// Invalid model specification
    23→    #[error("Invalid model: {0}")]
    24→    InvalidModel(String),
    25→}
    26→
    27→// Re-export important types for convenience
    28→pub use family::{Binomial, Gaussian, Poisson};
    29→pub use link::{Identity, Log, Logit};
    30→
    31→/// Common trait for all fitted models
    32→pub trait Fit {
    33→    /// Get model coefficients
    34→    fn coefficients(&self) -> &[f64];
    35→
    36→    /// Get fitted values
    37→    fn fitted(&self) -> &[f64];
    38→
    39→    /// Get residuals
    40→    fn residuals(&self) -> &[f64];
    41→
    42→    /// Get model summary
    43→    fn summary(&self) -> ModelSummary;
    44→}
    45→
    46→/// Model summary information
    47→#[derive(Debug)]
    48→pub struct ModelSummary {
    49→    /// Coefficient table
    50→    pub coefficients: Vec<CoefficientRow>,
    51→    /// R-squared (coefficient of determination)
    52→    pub r_squared: f64,
    53→    /// Adjusted R-squared
    54→    pub adj_r_squared: f64,
    55→    /// Residual standard error
    56→    pub residual_std_error: f64,
    57→    /// F-statistic for overall model significance
    58→    pub f_statistic: f64,
    59→    /// p-value for F-statistic
    60→    pub f_p_value: f64,
    61→    /// Degrees of freedom for model (number of predictors excluding intercept)
    62→    pub df_model: usize,
    63→    /// Degrees of freedom for residuals
    64→    pub df_residual: usize,
    65→}
    66→
    67→/// A row in the coefficient table
    68→#[derive(Debug)]
    69→pub struct CoefficientRow {
    70→    /// Variable name
    71→    pub name: String,
    72→    /// Estimated coefficient
    73→    pub estimate: f64,
    74→    /// Standard error
    75→    pub std_error: f64,
    76→    /// t-statistic
    77→    pub t_value: f64,
    78→    /// p-value
    79→    pub p_value: f64,
    80→}
    81→
    82→/// Linear model fitting
    83→pub struct Lm;
    84→
    85→/// Generalized linear model fitting
    86→pub struct Glm;
    87→
    88→/// Fitted linear model results
    89→#[derive(Debug)]
    90→pub struct LmFit {
    91→    coefficients: Vec<f64>,
    92→    fitted_values: Vec<f64>,
    93→    residuals: Vec<f64>,
    94→    /// Number of observations
    95→    n_obs: usize,
    96→    /// Matrix rank (for rank-deficient matrices)
    97→    rank: usize,
    98→    /// Design matrix for statistical inference (stored for covariance calculation)
    99→    x_matrix: Mat<f64>,
   100→}
   101→
   102→/// Fitted generalized linear model results
   103→#[derive(Debug)]
   104→pub struct GlmFit {
   105→    coefficients: Vec<f64>,
   106→    fitted_values: Vec<f64>,
   107→    residuals: Vec<f64>,
   108→    /// Linear predictor values (X * β)
   109→    linear_predictor: Vec<f64>,
   110→    /// Number of observations
   111→    n_obs: usize,
   112→    /// Design matrix for statistical inference
   113→    x_matrix: Mat<f64>,
   114→    /// Final deviance
   115→    deviance: f64,
   116→    /// Working weights from final IRLS iteration
   117→    weights: Vec<f64>,
   118→    /// Number of IRLS iterations
   119→    iterations: usize,
   120→    /// Whether IRLS converged
   121→    converged: bool,
   122→}
   123→
   124→impl Lm {
   125→    /// Fit a linear model using ndarray views (recommended modern API)
   126→    ///
   127→    /// This implementation uses faer's column-pivoted QR decomposition to handle
   128→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
   129→    ///
   130→    /// # Arguments
   131→    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
   132→    /// * `y` - Response vector as ndarray view (n_observations)
   133→    ///
   134→    /// # Example
   135→    /// ```
   136→    /// use ndarray::Array2;
   137→    /// use stats_models::Lm;
   138→    ///
   139→    /// // Create design matrix with intercept
   140→    /// let x = Array2::from_shape_vec((3, 2), vec![1.0, 1.0, 1.0, 2.0, 1.0, 3.0]).unwrap();
   141→    /// let y = vec![3.0, 5.0, 7.0];
   142→    ///
   143→    /// let fit = Lm::fit_ndarray(x.view(), ndarray::Array1::from(y).view()).unwrap();
   144→    /// ```
   145→    pub fn fit_ndarray(x: ArrayView2<f64>, y: ArrayView1<f64>) -> Result<LmFit, ModelError> {
   146→        let (n_rows, n_cols) = x.dim();
   147→
   148→        if y.len() != n_rows {
   149→            return Err(ModelError::InvalidModel(
   150→                "Response vector length doesn't match number of observations".to_string(),
   151→            ));
   152→        }
   153→
   154→        // Convert to faer matrices
   155→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
   156→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y[i]);
   157→
   158→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   159→    }
   160→
   161→    /// Fit a linear model using raw slices (legacy API for backward compatibility)
   162→    ///
   163→    /// This implementation uses faer's column-pivoted QR decomposition to handle
   164→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
   165→    ///
   166→    /// **Note**: Consider using `fit_ndarray` for better type safety and ergonomics.
   167→    pub fn fit(
   168→        x_data: &[f64],
   169→        y_data: &[f64],
   170→        n_rows: usize,
   171→        n_cols: usize,
   172→    ) -> Result<LmFit, ModelError> {
   173→        if x_data.len() != n_rows * n_cols {
   174→            return Err(ModelError::InvalidModel(
   175→                "Design matrix dimensions don't match data".to_string(),
   176→            ));
   177→        }
   178→
   179→        if y_data.len() != n_rows {
   180→            return Err(ModelError::InvalidModel(
   181→                "Response vector length doesn't match number of observations".to_string(),
   182→            ));
   183→        }
   184→
   185→        // Create faer matrices from input data
   186→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
   187→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);
   188→
   189→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   190→    }
   191→
   192→    /// Internal fitting logic shared by both APIs
   193→    fn fit_internal(
   194→        x_mat: Mat<f64>,
   195→        y_mat: Mat<f64>,
   196→        n_rows: usize,
   197→        n_cols: usize,
   198→    ) -> Result<LmFit, ModelError> {
   199→        // Use column-pivoted QR for numerical stability with rank-deficient matrices
   200→        let qr = x_mat.col_piv_qr();
   201→
   202→        // Calculate rank from R matrix diagonal elements
   203→        let r_matrix = qr.R();
   204→        let tolerance = 1e-12;
   205→        let mut rank = 0;
   206→        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
   207→            if r_matrix[(i, i)].abs() > tolerance {
   208→                rank += 1;
   209→            }
   210→        }
   211→
   212→        // Handle rank-deficient matrices by checking for numerical instability
   213→        let coefficients_mat = qr.solve_lstsq(&y_mat);
   214→
   215→        // Check for numerical instability and apply correction if needed
   216→        let has_instability =
   217→            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);
   218→
   219→        let final_coefficients_mat = if has_instability {
   220→            // For rank-deficient case, set coefficients for columns beyond rank to zero
   221→            let mut corrected_coefs = Vec::new();
   222→            for i in 0..coefficients_mat.nrows() {
   223→                let coef = coefficients_mat[(i, 0)];
   224→                if coef.abs() > 1e10 {
   225→                    corrected_coefs.push(0.0);
   226→                } else {
   227→                    corrected_coefs.push(coef);
   228→                }
   229→            }
   230→            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
   231→        } else {
   232→            coefficients_mat
   233→        };
   234→
   235→        // Calculate fitted values: ŷ = X * β (using corrected coefficients)
   236→        let fitted_mat = &x_mat * &final_coefficients_mat;
   237→
   238→        // Calculate residuals: e = y - ŷ
   239→        let residuals_mat = &y_mat - &fitted_mat;
   240→
   241→        // Extract results to plain Vec<f64> for API
   242→        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
   243→            .map(|i| final_coefficients_mat[(i, 0)])
   244→            .collect();
   245→
   246→        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
   247→            .map(|i| fitted_mat[(i, 0)])
   248→            .collect();
   249→
   250→        let residuals: Vec<f64> = (0..residuals_mat.nrows())
   251→            .map(|i| residuals_mat[(i, 0)])
   252→            .collect();
   253→
   254→        // rank is already computed above using qr.rank()
   255→
   256→        Ok(LmFit {
   257→            coefficients,
   258→            fitted_values,
   259→            residuals,
   260→            n_obs: n_rows,
   261→            rank,
   262→            x_matrix: x_mat,
   263→        })
   264→    }
   265→}
   266→
   267→impl LmFit {
   268→    /// Get the number of observations used in the model
   269→    pub fn n_obs(&self) -> usize {
   270→        self.n_obs
   271→    }
   272→
   273→    /// Get the rank of the design matrix (number of linearly independent columns)
   274→    pub fn rank(&self) -> usize {
   275→        self.rank
   276→    }
   277→
   278→    /// Get degrees of freedom for error (n_obs - rank)
   279→    pub fn df_resid(&self) -> usize {
   280→        self.n_obs.saturating_sub(self.rank)
   281→    }
   282→}
   283→
   284→impl Glm {
   285→    /// Fit a generalized linear model using ndarray views
   286→    ///
   287→    /// This implementation uses the IRLS algorithm to fit GLMs with any
   288→    /// exponential family distribution and link function.
   289→    ///
   290→    /// # Arguments
   291→    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
   292→    /// * `y` - Response vector as ndarray view (n_observations)
   293→    /// * `family` - Exponential family (Gaussian, Poisson, Binomial)
   294→    /// * `start` - Optional starting values for coefficients
   295→    /// * `config` - Optional IRLS configuration
   296→    pub fn fit_ndarray<F>(
   297→        x: ArrayView2<f64>,
   298→        y: ArrayView1<f64>,
   299→        family: F,
   300→        start: Option<Array1<f64>>,
   301→        config: Option<IrlsConfig>,
   302→    ) -> Result<GlmFit, ModelError>
   303→    where
   304→        F: Family,
   305→    {
   306→        let (n_rows, n_cols) = x.dim();
   307→
   308→        if y.len() != n_rows {
   309→            return Err(ModelError::InvalidModel(
   310→                "Response vector length doesn't match number of observations".to_string(),
   311→            ));
   312→        }
   313→
   314→        let link = family.link();
   315→
   316→        // Define closures for IRLS algorithm
   317→        let link_fn = |mu: f64| link.link(mu);
   318→        let inverse_link_fn = |eta: f64| link.inverse_link(eta);
   319→        let mu_eta_fn = |eta: f64| link.mu_eta(eta);
   320→        let variance_fn = |mu: f64| family.variance(mu);
   321→        let dev_resid_fn = |y: f64, mu: f64| family.dev_resid(y, mu);
   322→
   323→        let functions = optimcore::GlmFunctions {
   324→            link_fn,
   325→            inverse_link_fn,
   326→            mu_eta_fn,
   327→            variance_fn,
   328→            dev_resid_fn,
   329→        };
   330→
   331→        // Run IRLS algorithm
   332→        let irls_result = irls(x, y, functions, start, config)
   333→            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;
   334→
   335→        // Calculate fitted values: μ = g⁻¹(X * β)
   336→        let fitted_values: Vec<f64> = irls_result
   337→            .linear_predictor
   338→            .iter()
   339→            .map(|&eta| inverse_link_fn(eta))
   340→            .collect();
   341→
   342→        // Calculate residuals: e = y - μ
   343→        let residuals: Vec<f64> = y
   344→            .iter()
   345→            .zip(fitted_values.iter())
   346→            .map(|(&y_val, &fitted)| y_val - fitted)
   347→            .collect();
   348→
   349→        // Convert ndarray to faer matrix for storage
   350→        let x_matrix = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
   351→
   352→        Ok(GlmFit {
   353→            coefficients: irls_result.params.to_vec(),
   354→            fitted_values,
   355→            residuals,
   356→            linear_predictor: irls_result.linear_predictor.to_vec(),
   357→            n_obs: n_rows,
   358→            x_matrix,
   359→            deviance: irls_result.deviance,
   360→            weights: irls_result.weights.to_vec(),
   361→            iterations: irls_result.iterations,
   362→            converged: irls_result.converged,
   363→        })
   364→    }
   365→}
   366→
   367→impl GlmFit {
   368→    /// Get the number of observations used in the model
   369→    pub fn n_obs(&self) -> usize {
   370→        self.n_obs
   371→    }
   372→
   373→    /// Get the deviance
   374→    pub fn deviance(&self) -> f64 {
   375→        self.deviance
   376→    }
   377→
   378→    /// Get the number of IRLS iterations
   379→    pub fn iterations(&self) -> usize {
   380→        self.iterations
   381→    }
   382→
   383→    /// Check if IRLS converged
   384→    pub fn converged(&self) -> bool {
   385→        self.converged
   386→    }
   387→
   388→    /// Get the linear predictor values
   389→    pub fn linear_predictor(&self) -> &[f64] {
   390→        &self.linear_predictor
   391→    }
   392→
   393→    /// Get the working weights from final iteration
   394→    pub fn weights(&self) -> &[f64] {
   395→        &self.weights
   396→    }
   397→}
   398→
   399→impl Fit for LmFit {
   400→    fn coefficients(&self) -> &[f64] {
   401→        &self.coefficients
   402→    }
   403→
   404→    fn fitted(&self) -> &[f64] {
   405→        &self.fitted_values
   406→    }
   407→
   408→    fn residuals(&self) -> &[f64] {
   409→        &self.residuals
   410→    }
   411→
   412→    fn summary(&self) -> ModelSummary {
   413→        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};
   414→
   415→        // Calculate residual standard error: s² = RSS / (n - p)
   416→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   417→        let df_resid = self.df_resid() as f64;
   418→        let mse = if df_resid > 0.0 { rss / df_resid } else { 0.0 };
   419→        let residual_std_error = mse.sqrt();
   420→
   421→        // Calculate Total Sum of Squares (TSS) and R-squared
   422→        let y_mean: f64 = self
   423→            .fitted_values
   424→            .iter()
   425→            .zip(self.residuals.iter())
   426→            .map(|(fitted, resid)| fitted + resid) // y = fitted + residual
   427→            .sum::<f64>()
   428→            / self.n_obs as f64;
   429→
   430→        let tss: f64 = self
   431→            .fitted_values
   432→            .iter()
   433→            .zip(self.residuals.iter())
   434→            .map(|(fitted, resid)| {
   435→                let y = fitted + resid;
   436→                (y - y_mean).powi(2)
   437→            })
   438→            .sum();
   439→
   440→        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
   441→
   442→        // Adjusted R-squared: 1 - (RSS/(n-p)) / (TSS/(n-1))
   443→        let n = self.n_obs as f64;
   444→        let p = self.rank as f64;
   445→        let adj_r_squared = if n > 1.0 && p > 0.0 {
   446→            1.0 - (rss / (n - p)) / (tss / (n - 1.0))
   447→        } else {
   448→            r_squared
   449→        };
   450→
   451→        // F-statistic for overall model significance
   452→        // RSS for null model (intercept only) equals TSS
   453→        let df_model = if self.rank > 1 { self.rank - 1 } else { 0 }; // exclude intercept
   454→        let f_statistic = if df_model > 0 {
   455→            model_f_statistic(rss, tss, df_model, self.df_resid())
   456→        } else {
   457→            0.0
   458→        };
   459→
   460→        let f_p_value = if df_model > 0 && self.df_resid() > 0 {
   461→            f_test_p_value(f_statistic, df_model as i32, self.df_resid() as i32)
   462→        } else {
   463→            1.0
   464→        };
   465→
   466→        // Calculate variance-covariance matrix: σ² * (X'X)^(-1)
   467→        // Compute X'X
   468→        let xtx = self.x_matrix.transpose() * &self.x_matrix;
   469→
   470→        // Compute (X'X)^(-1) - use QR decomposition for numerical stability
   471→        let qr = xtx.col_piv_qr();
   472→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   473→        let xtx_inv = qr.solve(&identity);
   474→
   475→        // Standard errors are sqrt of diagonal elements of σ² * (X'X)^(-1)
   476→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   477→            .map(|i| (mse * xtx_inv[(i, i)]).sqrt())
   478→            .collect();
   479→
   480→        let t_stats = t_statistics(&self.coefficients, &std_errors);
   481→        let p_values = t_test_p_values(&t_stats, self.df_resid() as i32);
   482→
   483→        let mut coefficient_rows = Vec::new();
   484→        for (i, &coef) in self.coefficients.iter().enumerate() {
   485→            let name = if i == 0 {
   486→                "Intercept".to_string()
   487→            } else {
   488→                format!("X{}", i)
   489→            };
   490→
   491→            coefficient_rows.push(CoefficientRow {
   492→                name,
   493→                estimate: coef,
   494→                std_error: std_errors[i],
   495→                t_value: t_stats[i],
   496→                p_value: p_values[i],
   497→            });
   498→        }
   499→
   500→        ModelSummary {
   501→            coefficients: coefficient_rows,
   502→            r_squared,
   503→            adj_r_squared,
   504→            residual_std_error,
   505→            f_statistic,
   506→            f_p_value,
   507→            df_model,
   508→            df_residual: self.df_resid(),
   509→        }
   510→    }
   511→}
   512→
   513→impl Fit for GlmFit {
   514→    fn coefficients(&self) -> &[f64] {
   515→        &self.coefficients
   516→    }
   517→
   518→    fn fitted(&self) -> &[f64] {
   519→        &self.fitted_values
   520→    }
   521→
   522→    fn residuals(&self) -> &[f64] {
   523→        &self.residuals
   524→    }
   525→
   526→    fn summary(&self) -> ModelSummary {
   527→        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};
   528→
   529→        // For GLM, use deviance-based statistics
   530→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   531→        let n = self.n_obs as f64;
   532→        let p = self.coefficients.len() as f64;
   533→        let df_resid = (n - p).max(0.0);
   534→
   535→        // Use deviance for dispersion estimation in GLM
   536→        let dispersion = if df_resid > 0.0 {
   537→            self.deviance / df_resid
   538→        } else {
   539→            1.0
   540→        };
   541→        let residual_std_error = dispersion.sqrt();
   542→
   543→        // For GLM, R² is calculated differently (based on deviance)
   544→        // Null deviance would be calculated with intercept-only model
   545→        // For now, use a simplified version
   546→        let y_mean: f64 = self
   547→            .fitted_values
   548→            .iter()
   549→            .zip(self.residuals.iter())
   550→            .map(|(fitted, resid)| fitted + resid)
   551→            .sum::<f64>()
   552→            / n;
   553→
   554→        let tss: f64 = self
   555→            .fitted_values
   556→            .iter()
   557→            .zip(self.residuals.iter())
   558→            .map(|(fitted, resid)| {
   559→                let y = fitted + resid;
   560→                (y - y_mean).powi(2)
   561→            })
   562→            .sum();
   563→
   564→        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
   565→        let adj_r_squared = if n > 1.0 && p > 0.0 {
   566→            1.0 - (rss / df_resid) / (tss / (n - 1.0))
   567→        } else {
   568→            r_squared
   569→        };
   570→
   571→        // F-statistic for overall model significance
   572→        let df_model = if p > 1.0 { p as usize - 1 } else { 0 }; // exclude intercept
   573→        let f_statistic = if df_model > 0 {
   574→            model_f_statistic(rss, tss, df_model, df_resid as usize)
   575→        } else {
   576→            0.0
   577→        };
   578→
   579→        let f_p_value = if df_model > 0 && df_resid > 0.0 {
   580→            f_test_p_value(f_statistic, df_model as i32, df_resid as i32)
   581→        } else {
   582→            1.0
   583→        };
   584→
   585→        // Calculate variance-covariance matrix using weights
   586→        // For GLM: Var(β̂) = dispersion * (X'WX)^(-1)
   587→        let n_vars = self.coefficients.len();
   588→        let x_weighted = Mat::from_fn(self.n_obs, n_vars, |i, j| {
   589→            self.weights[i].sqrt() * self.x_matrix[(i, j)]
   590→        });
   591→
   592→        let xtx = x_weighted.transpose() * &x_weighted;
   593→        let qr = xtx.col_piv_qr();
   594→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   595→        let xtx_inv = qr.solve(&identity);
   596→
   597→        // Standard errors for GLM
   598→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   599→            .map(|i| (dispersion * xtx_inv[(i, i)]).sqrt())
   600→            .collect();
   601→
   602→        let t_stats = t_statistics(&self.coefficients, &std_errors);
   603→        let p_values = t_test_p_values(&t_stats, df_resid as i32);
   604→
   605→        let mut coefficient_rows = Vec::new();
   606→        for (i, &coef) in self.coefficients.iter().enumerate() {
   607→            let name = if i == 0 {
   608→                "Intercept".to_string()
   609→            } else {
   610→                format!("X{}", i)
   611→            };
   612→
   613→            coefficient_rows.push(CoefficientRow {
   614→                name,
   615→                estimate: coef,
   616→                std_error: std_errors[i],
   617→                t_value: t_stats[i],
   618→                p_value: p_values[i],
   619→            });
   620→        }
   621→
   622→        ModelSummary {
   623→            coefficients: coefficient_rows,
   624→            r_squared,
   625→            adj_r_squared,
   626→            residual_std_error,
   627→            f_statistic,
   628→            f_p_value,
   629→            df_model,
   630→            df_residual: df_resid as usize,
   631→        }
   632→    }
   633→}
